<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">      useIndicator</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 인디케이터 이벤트 내보내기 (기본값)</span></span>
